<span class="line"><span style="color:#ABB2BF;">                                   is_horizontal_fuse)(</span><span style="color:#E5C07B;">std</span><span style="color:#ABB2BF;">::</span><span style="color:#61AFEF;">move</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">fptr</span><span style="color:#ABB2BF;">-&gt;</span><span style="color:#E06C75;">body</span><span style="color:#ABB2BF;">));</span></span>
